// src/pages/LandingPage.jsx
import React, { useState } from 'react';
import { Link } from 'react-router-dom';

const explorePeople = [
  { name:'Aarav Shah',  avatar:'AS', level:'experienced', cat:'tech',     skills:['Python','ML','Data Science'],      rating:4.8, sessions:134, coins:45, bio:'ML engineer specialising in NLP and computer vision. I break down complex algorithms into intuitive intuitions.', location:'Pune, India',      completionRate:97,  responseTime:'< 1 hr'   },
  { name:'Mia Thomas',  avatar:'MT', level:'mid',         cat:'tech',     skills:['React','TypeScript','Next.js'],     rating:4.6, sessions:78,  coins:30, bio:'Frontend developer at a SaaS startup. I teach React from hooks to advanced patterns.',                          location:'Bengaluru', completionRate:94,  responseTime:'< 2 hrs'  },
  { name:'James Lee',   avatar:'JL', level:'mid',         cat:'tech',     skills:['SQL','PostgreSQL','DB Design'],     rating:4.5, sessions:55,  coins:28, bio:'Backend developer and database specialist. I focus on writing queries that actually perform.',                   location:'Chennai',   completionRate:91,  responseTime:'< 3 hrs'  },
  { name:'Riya Gupta',  avatar:'RG', level:'experienced', cat:'language', skills:['Spanish','French','IELTS'],         rating:4.9, sessions:162, coins:40, bio:'Language coach and certified DELF examiner. Lived in Paris for 3 years.',                                       location:'Delhi',     completionRate:99,  responseTime:'< 30 min' },
  { name:'Kiran Das',   avatar:'KD', level:'experienced', cat:'finance',  skills:['Finance','Options','Portfolio'],    rating:4.9, sessions:189, coins:50, bio:'Equity derivatives trader. I demystify options Greeks, portfolio construction, and risk management.',             location:'Mumbai',    completionRate:100, responseTime:'< 45 min' },
  { name:'Priya Nair',  avatar:'PN', level:'mid',         cat:'design',   skills:['UI/UX','Figma','Prototyping'],      rating:4.7, sessions:92,  coins:35, bio:'Product designer at a funded startup. I teach user research, wireframing, and polished Figma work.',            location:'Hyderabad', completionRate:95,  responseTime:'< 1.5 hrs'},
];

const leaderboard = [
  { name:'Kiran Das',   coins:12400, sessions:189, level:'experienced' },
  { name:'Riya Gupta',  coins:10800, sessions:162, level:'experienced' },
  { name:'Aarav Shah',  coins:9200,  sessions:134, level:'experienced' },
  { name:'Priya Nair',  coins:7600,  sessions:92,  level:'mid' },
  { name:'Mia Thomas',  coins:6100,  sessions:78,  level:'mid' },
  { name:'James Lee',   coins:4900,  sessions:55,  level:'mid' },
];

const LS = {
  experienced: { bg:'rgba(255,107,107,.15)', brd:'rgba(255,107,107,.3)', color:'#ff6b6b', icon:'🔥' },
  mid:         { bg:'rgba(108,99,255,.15)',  brd:'rgba(108,99,255,.3)',  color:'#6c63ff', icon:'⚡' },
  beginner:    { bg:'rgba(67,233,123,.15)',  brd:'rgba(67,233,123,.3)',  color:'#43e97b', icon:'🌱' },
};

const Stars = ({ r }) => [1,2,3,4,5].map(i =>
  <span key={i} style={{ color: i <= Math.round(r) ? '#ffd700' : 'var(--border)', fontSize:13 }}>★</span>
);

const LBadge = ({ level }) => {
  const s = LS[level] || LS.beginner;
  return <span style={{ display:'inline-flex', alignItems:'center', gap:4, padding:'2px 10px', borderRadius:100, fontSize:11, fontWeight:600, background:s.bg, border:`1px solid ${s.brd}`, color:s.color }}>{s.icon} {level}</span>;
};

const Pill = ({ children, onClick, active }) => (
  <button onClick={onClick} style={{ padding:'7px 18px', borderRadius:100, fontSize:13, fontWeight:600, cursor:'pointer', border:`1px solid ${active ? 'var(--accent)' : 'var(--border)'}`, background: active ? 'rgba(108,99,255,.2)' : 'var(--surface2)', color: active ? 'var(--accent)' : 'var(--muted)', transition:'all .15s' }}>{children}</button>
);

export default function LandingPage() {
  const [pg, setPg] = useState('home');
  const [sq, setSq] = useState('');
  const [lf, setLf] = useState('');
  const [cf, setCf] = useState('');

  const filtered = explorePeople.filter(p =>
    (!lf || p.level === lf) && (!cf || p.cat === cf) &&
    (!sq || p.name.toLowerCase().includes(sq.toLowerCase()) || p.skills.some(s => s.toLowerCase().includes(sq.toLowerCase())))
  );

  return (
    <div style={{ minHeight:'100vh', fontFamily:'Space Grotesk, sans-serif' }}>

      {/* NAV */}
      <nav style={{ position:'fixed', top:0, left:0, right:0, zIndex:100, display:'flex', alignItems:'center', justifyContent:'space-between', padding:'18px 48px', background:'rgba(10,10,15,0.9)', backdropFilter:'blur(20px)', borderBottom:'1px solid var(--border)' }}>
        <div onClick={() => setPg('home')} style={{ fontFamily:'Clash Display, sans-serif', fontSize:22, fontWeight:700, background:'linear-gradient(135deg,var(--accent),var(--accent2))', WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent', cursor:'pointer' }}>⚡ SkillSwap</div>
        <ul style={{ display:'flex', gap:32, listStyle:'none', margin:0 }}>
          {[['Home','home'],['Explore Skills','explore'],['How It Works','how'],['Leaderboard','leaderboard']].map(([l,p]) => (
            <li key={p}><span onClick={() => setPg(p)} style={{ color:pg===p?'var(--text)':'var(--muted)', fontSize:14, fontWeight:500, cursor:'pointer', borderBottom:pg===p?'2px solid var(--accent)':'2px solid transparent', paddingBottom:2 }}>{l}</span></li>
          ))}
        </ul>
        <div style={{ display:'flex', gap:12 }}>
          <Link to="/login"><button style={{ padding:'10px 22px', borderRadius:8, background:'transparent', color:'var(--muted)', border:'1px solid var(--border)', cursor:'pointer', fontFamily:'Space Grotesk', fontWeight:600, fontSize:14 }}>Sign In</button></Link>
          <Link to="/signup"><button style={{ padding:'10px 22px', borderRadius:8, background:'var(--accent)', color:'white', border:'none', cursor:'pointer', fontFamily:'Space Grotesk', fontWeight:600, fontSize:14 }}>Get Started</button></Link>
        </div>
      </nav>

      {/* ═══════ HOME ═══════ */}
      {pg === 'home' && (
        <div style={{ paddingTop:80 }}>
          <div style={{ display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', minHeight:'100vh', textAlign:'center', padding:'80px 24px 40px' }}>
            <div style={{ display:'inline-flex', alignItems:'center', gap:8, background:'rgba(108,99,255,.1)', border:'1px solid rgba(108,99,255,.3)', color:'#a09fff', padding:'6px 16px', borderRadius:100, fontSize:13, fontWeight:500, marginBottom:32 }}>
              <span style={{ width:6, height:6, background:'var(--accent3)', borderRadius:'50%' }} />
              Live Platform — 2,847 skills being traded right now
            </div>
            <h1 style={{ fontFamily:'Clash Display, sans-serif', fontSize:'clamp(48px,8vw,92px)', fontWeight:700, lineHeight:1.0, letterSpacing:'-2px', marginBottom:24 }}>
              Trade Skills.<br />
              <span style={{ background:'linear-gradient(135deg,var(--accent),var(--accent2),var(--accent3))', WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent' }}>Earn Real Value.</span>
            </h1>
            <p style={{ fontSize:20, color:'var(--muted)', maxWidth:560, lineHeight:1.6, marginBottom:48 }}>
              Share what you know. Learn what you don't. Every session earns you <strong style={{ color:'#ffd700' }}>SkillCoins</strong> redeemable as real money — verified, fair, anti-cheat.
            </p>
            <div style={{ display:'flex', gap:16, justifyContent:'center' }}>
              <Link to="/signup"><button style={{ padding:'14px 32px', borderRadius:8, background:'var(--accent)', color:'white', border:'none', cursor:'pointer', fontSize:16, fontWeight:600, fontFamily:'Space Grotesk' }}>Start Bartering Free →</button></Link>
              <button onClick={() => setPg('how')} style={{ padding:'14px 32px', borderRadius:8, background:'transparent', color:'var(--muted)', border:'1px solid var(--border)', cursor:'pointer', fontSize:16, fontWeight:600, fontFamily:'Space Grotesk' }}>See How It Works</button>
            </div>
            <div style={{ display:'flex', gap:48, marginTop:80, paddingTop:48, borderTop:'1px solid var(--border)', flexWrap:'wrap', justifyContent:'center' }}>
              {[['14K+','Registered Experts'],['89K','Sessions Completed'],['₹4.2Cr','Points Redeemed'],['340+','Skills Available']].map(([n,l]) => (
                <div key={n} style={{ textAlign:'center' }}>
                  <div style={{ fontFamily:'Clash Display, sans-serif', fontSize:36, fontWeight:700, color:'var(--accent)' }}>{n}</div>
                  <div style={{ fontSize:13, color:'var(--muted)', marginTop:4 }}>{l}</div>
                </div>
              ))}
            </div>
          </div>

          {/* Features */}
          <div style={{ maxWidth:1200, margin:'0 auto', padding:'80px 24px' }}>
            <p style={{ textAlign:'center', fontSize:13, letterSpacing:2, textTransform:'uppercase', color:'var(--accent)', marginBottom:12 }}>Platform Features</p>
            <h2 style={{ fontFamily:'Clash Display, sans-serif', fontSize:36, fontWeight:700, textAlign:'center', marginBottom:48 }}>Everything you need to<br />trade knowledge fairly</h2>
            <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:24 }}>
              {[['🎯','Skill Verification Exams','LeetCode-style coding challenges + knowledge tests. AI-powered plagiarism detection ensures your verified badge is earned, not copied.'],['🔄','Smart Skill Matching','Tell us what you know and want to learn. Our algorithm connects you with the perfect barter partner instantly.'],['💰','SkillCoin Economy','Earn points for every session you teach. Redeem as real money via UPI, bank transfer, or Amazon Pay.'],['🏆','3-Tier Level System','Beginner → Mid → Experienced. Level up by passing harder exams. Higher levels earn more points.'],['🛡️','Anti-Plagiarism Engine','Real-time code similarity detection, browser focus tracking, and randomized questions prevent cheating.'],['⭐','Rating & Reviews','Both teacher and learner rate each session. Build your reputation and unlock premium earning tiers.']].map(([icon,title,desc]) => (
                <div key={title} style={{ background:'var(--surface)', border:'1px solid var(--border)', borderRadius:16, padding:24, transition:'all .2s' }}
                  onMouseOver={e => { e.currentTarget.style.borderColor='var(--accent)'; e.currentTarget.style.transform='translateY(-2px)'; e.currentTarget.style.boxShadow='0 12px 40px rgba(108,99,255,.15)'; }}
                  onMouseOut={e => { e.currentTarget.style.borderColor='var(--border)'; e.currentTarget.style.transform=''; e.currentTarget.style.boxShadow=''; }}>
                  <div style={{ fontSize:32, marginBottom:16 }}>{icon}</div>
                  <h3 style={{ fontFamily:'Clash Display, sans-serif', fontSize:20, marginBottom:10 }}>{title}</h3>
                  <p style={{ color:'var(--muted)', fontSize:14, lineHeight:1.7 }}>{desc}</p>
                </div>
              ))}
            </div>
          </div>

          {/* Levels */}
          <div style={{ background:'var(--surface)', borderTop:'1px solid var(--border)', borderBottom:'1px solid var(--border)', padding:'80px 0' }}>
            <div style={{ maxWidth:1200, margin:'0 auto', padding:'0 24px' }}>
              <h2 style={{ fontFamily:'Clash Display, sans-serif', fontSize:36, fontWeight:700, marginBottom:8 }}>Skill Levels & Earnings</h2>
              <p style={{ color:'var(--muted)', fontSize:16, marginBottom:48 }}>Prove your expertise — earn more as you level up</p>
              <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:24 }}>
                {[
                  { level:'beginner', label:'🌱 Beginner', coins:'5–15', brd:'rgba(67,233,123,.3)', color:'var(--accent3)', perks:['✓ 1 skill verified','✓ Basic exam passed','✓ Community access','✗ Premium matching'] },
                  { level:'mid', label:'⚡ Mid-Level', coins:'20–50', brd:'rgba(108,99,255,.5)', color:'var(--accent)', perks:['✓ 3+ skills verified','✓ Intermediate exam','✓ Priority matching','✓ Group sessions'], popular:true },
                  { level:'experienced', label:'🔥 Experienced', coins:'60–150', brd:'rgba(255,107,107,.3)', color:'var(--accent2)', perks:['✓ Expert exam verified','✓ Top matching queue','✓ Mentor badge','✓ Bonus multipliers'] },
                ].map(l => (
                  <div key={l.level} style={{ background:'var(--surface)', border:`1px solid ${l.brd}`, borderRadius:16, padding:36, textAlign:'center', transform:l.popular?'scale(1.04)':'none', boxShadow:l.popular?'0 20px 60px rgba(108,99,255,.2)':'none', position:'relative' }}>
                    {l.popular && <div style={{ position:'absolute', top:-14, left:'50%', transform:'translateX(-50%)', background:'var(--accent)', color:'white', fontSize:11, fontWeight:700, padding:'4px 16px', borderRadius:100 }}>POPULAR</div>}
                    <LBadge level={l.level} />
                    <div style={{ fontFamily:'Clash Display, sans-serif', fontSize:40, fontWeight:700, color:l.color, margin:'16px 0' }}>{l.coins}</div>
                    <div style={{ color:'var(--muted)', fontSize:14 }}>coins per 30-min session</div>
                    <div style={{ marginTop:20, color:'var(--muted)', fontSize:13, lineHeight:2.0 }}>{l.perks.map((p,i)=><div key={i}>{p}</div>)}</div>
                  </div>
                ))}
              </div>
              <p style={{ textAlign:'center', marginTop:32, color:'var(--muted)', fontSize:14 }}>💡 100 SkillCoins = ₹100 redeemable via UPI/Bank Transfer</p>
            </div>
          </div>
        </div>
      )}

      {/* ═══════ HOW IT WORKS ═══════ */}
      {pg === 'how' && (
        <div style={{ maxWidth:900, margin:'0 auto', padding:'120px 24px 80px' }}>
          <h1 style={{ fontFamily:'Clash Display, sans-serif', fontSize:48, fontWeight:700, marginBottom:8 }}>How SkillSwap Works</h1>
          <p style={{ color:'var(--muted)', fontSize:18, marginBottom:48 }}>From registration to real earnings in 4 simple steps</p>
          {[
            ['01','Register & Declare Your Skills','Sign up and tell us what skills you have (teaching) and what you want to learn. Choose from 340+ categories including programming, design, marketing, languages, music, finance, and more.'],
            ['02','Take the Skill Verification Exam','Each skill requires passing a timed test — LeetCode-style coding for tech, MCQ + practical for others. Our AI anti-plagiarism engine monitors browser focus and code similarity in real time.'],
            ['03','Get Matched & Start Sessions','Our smart algorithm matches you with someone who has what you want to learn and wants what you know. Schedule a live 1-on-1 or group session — true barter!'],
            ['04','Earn SkillCoins → Redeem as Money','Every session you teach earns SkillCoins based on your level. Accumulate coins and redeem them as real money — minimum ₹200 withdrawal via UPI, bank transfer, or Amazon Pay.'],
          ].map(([num, title, desc]) => (
            <div key={num} style={{ display:'flex', gap:24, alignItems:'flex-start', padding:'28px 0', borderBottom:'1px solid var(--border)' }}>
              <div style={{ fontFamily:'Clash Display, sans-serif', fontSize:48, fontWeight:700, color:'var(--border)', lineHeight:1, minWidth:60 }}>{num}</div>
              <div>
                <h3 style={{ fontFamily:'Clash Display, sans-serif', fontSize:22, marginBottom:10 }}>{title}</h3>
                <p style={{ color:'var(--muted)', fontSize:15, lineHeight:1.7 }}>{desc}</p>
              </div>
            </div>
          ))}
          <div style={{ marginTop:48, textAlign:'center' }}>
            <Link to="/signup"><button style={{ padding:'14px 36px', borderRadius:8, background:'var(--accent)', color:'white', border:'none', cursor:'pointer', fontSize:16, fontWeight:600, fontFamily:'Space Grotesk' }}>Join Now — It's Free</button></Link>
          </div>
        </div>
      )}

      {/* ═══════ EXPLORE ═══════ */}
      {pg === 'explore' && (
        <div style={{ maxWidth:1200, margin:'0 auto', padding:'120px 24px 80px' }}>
          <h1 style={{ fontFamily:'Clash Display, sans-serif', fontSize:40, fontWeight:700, marginBottom:8 }}>Explore Skills</h1>
          <p style={{ color:'var(--muted)', fontSize:16, marginBottom:32 }}>Find experts to learn from or people who need your knowledge</p>
          <div style={{ display:'flex', gap:12, marginBottom:24, flexWrap:'wrap' }}>
            <input value={sq} onChange={e=>setSq(e.target.value)} placeholder="Search skills, topics, people..." style={{ flex:1, minWidth:240, background:'var(--surface2)', border:'1px solid var(--border)', color:'var(--text)', padding:'12px 16px', borderRadius:10, fontFamily:'Space Grotesk', fontSize:15, outline:'none' }} />
            <select value={lf} onChange={e=>setLf(e.target.value)} style={{ background:'var(--surface2)', border:'1px solid var(--border)', color:'var(--text)', padding:'12px 16px', borderRadius:10, fontFamily:'Space Grotesk', fontSize:14, outline:'none' }}>
              <option value="">All Levels</option><option value="experienced">🔥 Experienced</option><option value="mid">⚡ Mid-Level</option><option value="beginner">🌱 Beginner</option>
            </select>
            <select value={cf} onChange={e=>setCf(e.target.value)} style={{ background:'var(--surface2)', border:'1px solid var(--border)', color:'var(--text)', padding:'12px 16px', borderRadius:10, fontFamily:'Space Grotesk', fontSize:14, outline:'none' }}>
              <option value="">All Categories</option><option value="tech">💻 Tech</option><option value="design">🎨 Design</option><option value="language">🌐 Language</option><option value="finance">📈 Finance</option>
            </select>
          </div>
          <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:20 }}>
            {filtered.map((p, i) => {
              const ls = LS[p.level] || LS.beginner;
              return (
                <div key={i} style={{ background:'var(--surface)', border:'1px solid var(--border)', borderRadius:16, padding:20, transition:'all .2s' }}
                  onMouseOver={e => { e.currentTarget.style.borderColor='var(--accent)'; e.currentTarget.style.transform='translateY(-2px)'; e.currentTarget.style.boxShadow='0 12px 40px rgba(108,99,255,.15)'; }}
                  onMouseOut={e => { e.currentTarget.style.borderColor='var(--border)'; e.currentTarget.style.transform=''; e.currentTarget.style.boxShadow=''; }}>
                  <div style={{ display:'flex', gap:12, alignItems:'flex-start', marginBottom:12 }}>
                    <div style={{ width:48, height:48, borderRadius:'50%', background:'linear-gradient(135deg,var(--accent),var(--accent2))', display:'flex', alignItems:'center', justifyContent:'center', fontFamily:'Clash Display', fontWeight:700, fontSize:18, color:'white', flexShrink:0 }}>{p.avatar}</div>
                    <div style={{ flex:1 }}>
                      <div style={{ display:'flex', gap:8, alignItems:'center', flexWrap:'wrap', marginBottom:4 }}>
                        <span style={{ fontFamily:'Clash Display, sans-serif', fontWeight:700, fontSize:16 }}>{p.name}</span>
                        <LBadge level={p.level} />
                      </div>
                      <div style={{ display:'flex', gap:2 }}><Stars r={p.rating} /><span style={{ color:'var(--muted)', fontSize:12, marginLeft:4 }}>{p.rating} · {p.sessions} sessions</span></div>
                    </div>
                  </div>
                  <p style={{ fontSize:13, color:'var(--muted)', marginBottom:12, lineHeight:1.5, display:'-webkit-box', WebkitLineClamp:2, WebkitBoxOrient:'vertical', overflow:'hidden' }}>{p.bio}</p>
                  <div style={{ display:'flex', flexWrap:'wrap', gap:5, marginBottom:12 }}>
                    {p.skills.map(s=><span key={s} style={{ background:'var(--surface2)', border:'1px solid var(--border)', padding:'3px 10px', borderRadius:100, fontSize:11, color:'var(--muted)' }}>{s}</span>)}
                  </div>
                  <div style={{ fontSize:12, color:'var(--muted)', marginBottom:12 }}>📍 {p.location} · ⏱️ {p.responseTime} · ✅ {p.completionRate}%</div>
                  <div style={{ display:'flex', gap:8, alignItems:'center' }}>
                    <span style={{ color:'#ffd700', fontFamily:'JetBrains Mono, monospace', fontSize:13, flex:1 }}>🪙 {p.coins} coins/session</span>
                    <Link to="/signup"><button style={{ padding:'6px 14px', borderRadius:8, background:'var(--accent)', color:'white', border:'none', cursor:'pointer', fontSize:12, fontWeight:600, fontFamily:'Space Grotesk' }}>Connect</button></Link>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* ═══════ LEADERBOARD ═══════ */}
      {pg === 'leaderboard' && (
        <div style={{ maxWidth:700, margin:'0 auto', padding:'120px 24px 80px' }}>
          <h1 style={{ fontFamily:'Clash Display, sans-serif', fontSize:40, fontWeight:700, marginBottom:8 }}>🏆 Leaderboard</h1>
          <p style={{ color:'var(--muted)', fontSize:16, marginBottom:32 }}>Top earners this month — compete for bonus multipliers</p>
          <div style={{ background:'var(--surface)', border:'1px solid var(--border)', borderRadius:16, padding:8 }}>
            {leaderboard.map((u, i) => {
              const ls = LS[u.level] || LS.beginner;
              const medal = i===0?'🥇':i===1?'🥈':i===2?'🥉':null;
              return (
                <div key={i} style={{ display:'flex', alignItems:'center', gap:16, padding:'16px 20px', borderRadius:12, transition:'background .2s' }}
                  onMouseOver={e => e.currentTarget.style.background='var(--surface2)'}
                  onMouseOut={e => e.currentTarget.style.background='transparent'}>
                  <div style={{ fontFamily:'Clash Display, sans-serif', fontSize:20, fontWeight:700, width:32, textAlign:'center', color:i===0?'#ffd700':i===1?'#c0c0c0':i===2?'#cd7f32':'var(--muted)' }}>{medal || i+1}</div>
                  <div style={{ width:40, height:40, borderRadius:'50%', background:'linear-gradient(135deg,var(--accent),var(--accent2))', display:'flex', alignItems:'center', justifyContent:'center', fontFamily:'Clash Display', fontWeight:700, fontSize:16, color:'white' }}>{u.name[0]}</div>
                  <div style={{ flex:1 }}>
                    <div style={{ fontWeight:600, fontSize:15 }}>{u.name}</div>
                    <LBadge level={u.level} />
                  </div>
                  <div style={{ textAlign:'right' }}>
                    <div style={{ fontFamily:'JetBrains Mono, monospace', fontSize:14, color:'#ffd700', fontWeight:600 }}>🪙 {u.coins.toLocaleString()}</div>
                    <div style={{ fontSize:11, color:'var(--muted)' }}>{u.sessions} sessions</div>
                  </div>
                </div>
              );
            })}
          </div>
          <div style={{ marginTop:32, textAlign:'center' }}>
            <Link to="/signup"><button style={{ padding:'13px 36px', borderRadius:8, background:'linear-gradient(135deg,#ffd700,#ffaa00)', color:'#1a1100', fontWeight:700, fontSize:15, border:'none', cursor:'pointer', fontFamily:'Space Grotesk' }}>Join & Start Earning 🪙</button></Link>
          </div>
        </div>
      )}
    </div>
  );
}
